    udp_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    for ip in TargetIP:
        payload_bytes = bytes.fromhex(payload)
        udp_socket.sendto(payload_bytes, (f"{ip}", Port))
    udp_socket.close()
