KONAMI_CODE = ['Up', 'Up', 'Down', 'Down', 'Left', 'Right', 'Left', 'Right', 'b', 'a', 'b', 'a']  # 科乐美秘籍

def check_konami_code(event):
    """检测科乐美秘钥输入"""
    global admin_mode, konami_sequence
    
    # 获取按键名称
    key = event.keysym
    
    # 添加到序列中
    konami_sequence.append(key)
    
    # 保持序列长度不超过秘钥长度
    if len(konami_sequence) > len(KONAMI_CODE):
        konami_sequence.pop(0)
    
    # 检查是否匹配
    if len(konami_sequence) == len(KONAMI_CODE):
        if konami_sequence == KONAMI_CODE:
            # 激活管理员模式
            admin_mode = True
            konami_sequence.clear()
            
            # 更改窗口标题显示管理员模式
            root.title('X反极域 v3.0 [管理员模式]')
            
            # 显示提示
